-- カテゴリB「商品知識：symphonyシリーズ」の研修テスト作成
-- category_tests に1件 + category_test_questions に50問を挿入

-- シーケンスを最新 id に合わせてから挿入
SELECT setval('category_tests_id_seq', (SELECT MAX(id) FROM category_tests), true);
SELECT setval('category_test_questions_id_seq', (SELECT MAX(id) FROM category_test_questions), true);

SELECT 'B', '商品知識：symphonyシリーズ編', 50, 80, 30
WHERE NOT EXISTS (SELECT 1 FROM category_tests WHERE category_id = 'B');

DO $$
DECLARE
  v_test_id INT;
BEGIN
  SELECT id INTO v_test_id FROM category_tests WHERE category_id = 'B' ORDER BY id DESC LIMIT 1;

  IF NOT EXISTS (SELECT 1 FROM category_test_questions WHERE category_test_id = v_test_id) THEN
  END IF;
END $$;
