INSERT INTO public.category_tests (category_id, category_name, total_questions, passing_score, time_limit)
    INSERT INTO category_test_questions (category_test_id, question_number, question, options, correct_answer, explanation, source) VALUES
    (v_test_id,1,'symphonyシリーズの3つの価値として正しいものは？','["分かりやすい・つながる・売上が伸びる","信頼・実績・サポート","品質・価格・サービス","安い・早い・うまい"]'::jsonb,0,'symphonyは「分かりやすい」「つながる」「売上が伸びる」の3つの価値を提供します。','研修11: symphonyシリーズ全体像'),
    (v_test_id,2,'symphonyシリーズが解決する中古車販売店の主な課題は？','["スタッフ不足","複数システムへの二重入力・手書き管理の非効率","店舗面積の狭さ","駐車場の不足"]'::jsonb,1,'中古車販売店では複数システムへの二重入力や手書き管理が大きな課題であり、symphonyはこれを解決します。','研修11: symphonyシリーズ全体像'),
    (v_test_id,3,'symphonyシリーズの中心となるコア製品は？','["symphony ワンプラ","symphony インサイト","symphony 販売管理","symphony 整備請求"]'::jsonb,2,'symphony 販売管理が中心製品で、ワンプラや整備請求と連携してさらに価値を発揮します。','研修11: symphonyシリーズ全体像'),
    (v_test_id,4,'symphonyシリーズのメイン製品の組み合わせとして正しいものは？','["販売管理・ワンプラの2製品","販売管理・整備請求・ワンプラの3製品","販売管理・整備請求・ワンプラ・インサイトの4製品","5製品以上"]'::jsonb,1,'symphonyシリーズには販売管理・整備請求・ワンプラの3つのメイン製品があります。','研修11: symphonyシリーズ全体像'),
    (v_test_id,5,'中古車販売店が「業務が回らない」と感じる主な理由として正しいのは？','["スタッフの能力不足","仕入れ価格の高騰","在庫管理・広告掲載・顧客管理が全てバラバラで二重・三重手間になっている","競合店舗の増加"]'::jsonb,2,'複数のシステムが連携しておらず、同じデータを何度も入力する二重・三重手間が非効率の根源でした。','研修11: symphonyシリーズ全体像'),
    (v_test_id,6,'symphony 販売管理で一括掲載できるメディア数は？','["5サイト以上","3サイト以上","20サイト以上","10サイト以上"]'::jsonb,3,'カーセンサー、グーネット、Yahoo!オークションなど10以上のメディアに一括掲載できます。','研修12: symphony 販売管理'),
    (v_test_id,7,'symphony 販売管理の「一度の入力で、すべて完結」というキーフレーズが意味することは？','["データのバックアップが自動化される","車両情報を1度登録すれば複数メディアへの掲載と各業務への連携が自動で行われる","月1回の更新で1ヶ月分の在庫が管理できる","1名のスタッフだけで全業務が完結する"]'::jsonb,1,'車両情報を一度登録するだけで複数の広告メディアへの掲載と社内各業務への情報連携が自動で行われます。','研修12: symphony 販売管理'),
    (v_test_id,8,'symphony 販売管理が他社システムと差別化される最大の理由は？','["価格が安い","サポートが丁寧","symphonyシリーズ全体と連携しワンプラ・整備請求とのデータ連携ができる","海外でも使える"]'::jsonb,2,'単体機能ではなく、ワンプラや整備請求との連携により業務全体を一元化できる点が最大の差別化ポイントです。','研修12: symphony 販売管理'),
    (v_test_id,9,'symphony 販売管理で自動化される主な業務として正しいものは？','["来店接客","電話応対","在庫広告の一括掲載・粗利計算","試乗の予約管理"]'::jsonb,2,'広告の一括掲載、粗利計算の自動化などが主な自動化業務です。接客はシステムで代替できません。','研修12: symphony 販売管理'),
    (v_test_id,10,'導入事例①でsymphony 販売管理導入後、成約率はどの程度向上したか？','["5%向上","30%向上","50%向上","15%向上"]'::jsonb,3,'事務作業が3分の1に短縮されたことで接客時間が確保でき、成約率が15%向上しました。','研修12: symphony 販売管理'),
    (v_test_id,11,'symphony 販売管理の「1+1を3にする」という表現が意味することは？','["2製品を導入すれば必ず3倍の売上になる","単体導入より複数連携の方が相乗効果が大きい","1店舗に3名スタッフを配置する","1日に3件の提案をする"]'::jsonb,1,'単体製品の価値を超えて、連携することで相乗効果が生まれることを表しています。','研修12: symphony 販売管理'),
    (v_test_id,12,'各サイトへの個別入力で毎日かかっていたおおよその時間は？','["約30分","約5時間","約2〜3時間","約1時間未満"]'::jsonb,2,'各サイトへの個別入力により1日2〜3時間以上の作業が発生しており、symphonyが大幅に削減します。','研修12: symphony 販売管理'),
    (v_test_id,13,'symphony 整備請求が解決する主な課題として正しいのは？','["新車の発注管理","見積・請求書が手書きやExcelで非効率・車検時期の管理漏れ","スタッフのシフト管理","広告の制作業務"]'::jsonb,1,'整備請求では見積・請求書の一元化と車検時期の自動アラートにより業務効率化とフォロー漏れを防ぎます。','研修13: symphony 整備請求'),
    (v_test_id,14,'symphony 整備請求と販売管理を連携させた場合のメリットは？','["保険の手続きが簡単になる","在庫が増える","顧客情報が共有され販売→整備→再販売のサイクルでLTVを最大化できる","ローンの審査が通りやすくなる"]'::jsonb,2,'販売時の顧客情報が整備に引き継がれ、車検・点検フォローで顧客の生涯価値（LTV）を最大化できます。','研修13: symphony 整備請求'),
    (v_test_id,15,'symphony 整備請求で車検時期はどのように管理されるか？','["スタッフが手動で確認する","自動アラートで通知される","月次レポートで確認する","顧客自身がシステムに登録する"]'::jsonb,1,'車検時期は自動アラートで通知されるため、フォロー漏れを防げます。','研修13: symphony 整備請求'),
    (v_test_id,16,'整備請求のキーフレーズ「販売後も、つながり続ける」が示す価値は？','["販売後のアフターサービスで継続的な顧客関係を築く","車を売った後も販売管理システムを使い続ける","販売担当者が退職後も会社に貢献する","顧客が複数台購入し続ける"]'::jsonb,0,'販売後も整備・車検フォローを通じて顧客との関係を継続し、リピートビジネスを創出するという価値を表しています。','研修13: symphony 整備請求'),
    (v_test_id,17,'symphony 整備請求導入後のリピート率向上幅は？','["5%向上","50%向上","30%向上","15%向上"]'::jsonb,3,'車検アラートによる適切なフォローにより、リピート率が15%向上しました。','研修13: symphony 整備請求'),
    (v_test_id,18,'symphony 整備請求の「見積から請求まで一元管理」が実現することは？','["見積と請求を別々のスタッフが担当できる","整備作業の手書き書類をデジタルで一元管理できる","顧客が自分で見積を作成できる","銀行への振込が自動化される"]'::jsonb,1,'手書きやExcelで行っていた見積・請求書作業をシステム上で一元管理できるようになります。','研修13: symphony 整備請求'),
    (v_test_id,19,'symphony ワンプラの共有在庫数は？','["約3万台","約1万台","約7万台","約10万台"]'::jsonb,2,'symphony ワンプラは全国の中古車販売店をつなぐプラットフォームで、約7万台の共有在庫から仕入れが可能です。','研修14: symphony ワンプラ'),
    (v_test_id,20,'symphony ワンプラの手数料体系として正しいものは？','["月額固定費のみ","年会費制","出品成約料と落札料（成約時のみ発生・固定費ゼロ）","売上の一定割合"]'::jsonb,2,'ワンプラは出品成約料と落札料の2種類で、成約時のみ発生します。固定費はゼロなのでリスクなく始められます。','研修14: symphony ワンプラ'),
    (v_test_id,21,'symphony ワンプラで仕入れができる時間帯は？','["平日9時〜18時のみ","24時間365日","土日祝日を除く平日のみ","オークション開催日のみ"]'::jsonb,1,'ワンプラは24時間いつでも仕入れができます。オークションの開催日時に縛られません。','研修14: symphony ワンプラ'),
    (v_test_id,22,'ワンプラのキーフレーズ「在庫を流動化、コストを最小化」が示す価値は？','["店舗の物理的スペースを削減する","長期在庫を業販出品しながら必要な車を低コストで仕入れる","仕入れコストをゼロにする","在庫数を最小限に保つ"]'::jsonb,1,'売れない在庫を全国の業者に出品して資金化しながら、必要な車を低コストで仕入れられる価値を示しています。','研修14: symphony ワンプラ'),
    (v_test_id,23,'ワンプラを導入することで解決できる仕入れの課題は？','["オークション相場の節約","特定のオークション会場に縛られず全国7万台から仕入れできる","外車の輸入が容易になる","新車ディーラーとの取引が増える"]'::jsonb,1,'全国のネットワークから24時間仕入れができるため、欲しい車が見つかりやすくなります。','研修14: symphony ワンプラ'),
    (v_test_id,24,'symphony ワンプラを活用した長期在庫の対処方法として最も適切なのは？','["値引きして早期販売する","全国の業者に業販出品して在庫回転率を上げる","廃車にしてコストを削減する","オークション会場のみに出品する"]'::jsonb,1,'ワンプラを使って長期在庫を全国の業者に業販出品することで、在庫回転率を上げられます。','研修14: symphony ワンプラ'),
    (v_test_id,25,'symphony 販売管理とワンプラを連携した場合の最大のメリットは？','["割引料金が適用される","在庫データが自動連携されワンプラへの出品作業がゼロになる","車両の輸送が無料になる","担当サポートが専任でつく"]'::jsonb,1,'販売管理に登録した在庫データが自動でワンプラに出品されるため、二重入力の手間がなくなります。','研修14: symphony ワンプラ'),
    (v_test_id,26,'ワンプラの競合優位性として最も強調すべきポイントは？','["歴史が長い","デザインが優れている","固定費ゼロ＋symphony連携による在庫自動出品","サポートセンターが24時間対応"]'::jsonb,2,'成約時のみ手数料発生（固定費ゼロ）と、symphony連携で在庫データが自動出品できる点が最大の差別化です。','研修15: ワンプラの競合比較'),
    (v_test_id,27,'競合サービスと比較した場合のワンプラの優位点は？','["競合より在庫台数が多い","月額費用がなく取引件数に関わらずコストを抑えられる","海外ネットワークがある","新車も扱える"]'::jsonb,1,'競合A社には月額費用がかかる場合が多く、ワンプラは成約時のみの手数料なので低リスクで導入できます。','研修15: ワンプラの競合比較'),
    (v_test_id,28,'顧客に「他社サービスも検討している」と言われた場合の最適な対応は？','["他社の悪口を言う","値引きを提案する","具体的な数字で年間コスト差を示しsymphony連携の付加価値を伝える","検討期間を長く設ける"]'::jsonb,2,'競合比較では感情論ではなく具体的なコスト差を数字で示し、symphony連携という独自の付加価値を訴求することが有効です。','研修15: ワンプラの競合比較'),
    (v_test_id,29,'ワンプラ競合比較で使う「ROIを数字で語る」アプローチとは？','["感情に訴えて購入を促す","月10台取引時の年間コスト差など具体的な金額で優位性を示す","競合製品の機能一覧を見せる","他の顧客の感想を伝える"]'::jsonb,1,'「月10台取引なら年間約○万円の差」のように顧客の実情に合わせた具体的な金額でROIを示すことが説得力を高めます。','研修15: ワンプラの競合比較'),
    (v_test_id,30,'symphonyシリーズ製品間連携の核心的なメリットは？','["サポートが一本化される","価格が割引になる","データが自動連携され二重入力が不要になる","一つの担当者が対応する"]'::jsonb,2,'製品間でデータが自動連携されるため、各システムへの二重入力が不要になります。','研修16: 製品間連携の価値'),
    (v_test_id,31,'「1+1を3にする」という表現で説明される連携効果とは？','["2製品を導入すれば必ず3倍の売上になる","製品単体の価値を超えた相乗効果が生まれる","3製品目は無料になる","サポートが3倍手厚くなる"]'::jsonb,1,'単体製品の機能の合計を超えた相乗効果、すなわちデータ連携・業務自動化・顧客フォローの自動化が実現することを指します。','研修16: 製品間連携の価値'),
    (v_test_id,32,'クロスセル提案のタイミングとして最も適切なのはいつか？','["初回商談時に全製品を提案する","契約直後に追加提案する","導入後に効果を実感し始めた頃に追加価値を提案する","解約を申し出た時"]'::jsonb,2,'顧客が既存製品の効果を実感した後にクロスセルを提案するのが最も自然で効果的です。','研修16: 製品間連携の価値'),
    (v_test_id,33,'symphony 販売管理とワンプラの連携でなくなる作業は？','["来店対応","車両の写真撮影","ワンプラへの在庫手動出品","試乗の手配"]'::jsonb,2,'販売管理に登録した在庫データがワンプラに自動連携されるため、ワンプラへの手動出品作業がなくなります。','研修16: 製品間連携の価値'),
    (v_test_id,34,'販売管理・整備請求・ワンプラをフル活用した場合の期待効果として誤っているのは？','["在庫回転率の向上","リピート顧客の増加","事務作業時間の大幅削減","新車ディーラーとの提携が自動的に成立する"]'::jsonb,3,'symphonyシリーズは中古車販売業務の効率化と売上向上に貢献しますが、新車ディーラーとの提携はシステムがもたらす効果ではありません。','研修16: 製品間連携の価値'),
    (v_test_id,35,'小規模店舗（オーナー1人・在庫8台）がsymphony導入前に抱えていた最大の課題は？','["スタッフ採用が難しい","1日3時間以上の事務作業で接客に時間を割けない","仕入れ先が見つからない","店舗の家賃が高い"]'::jsonb,1,'手書き在庫管理と各広告サイトへの個別入力で1日3時間以上かかっており、接客時間が取れない状態でした。','研修17: 導入事例研究①'),
    (v_test_id,36,'symphony 販売管理導入後、小規模店舗Aの広告掲載作業はどの程度効率化されたか？','["2倍速くなった","10分の1になった","3分の1に短縮された","ほぼ変わらなかった"]'::jsonb,2,'一括掲載機能により広告掲載作業が従来の3分の1に短縮されました。','研修17: 導入事例研究①'),
    (v_test_id,37,'小規模店舗への提案で「事務作業削減→接客強化→売上アップ」が響く理由は？','["小規模店舗は価格が最優先だから","オーナーが1人で全業務をこなす中で接客時間の確保が売上に直結するから","小規模店舗はデジタル化に積極的だから","競合が少ないから"]'::jsonb,1,'少ない人数で全業務をこなすオーナーにとって、事務効率化による接客強化が最も直接的に売上に影響するからです。','研修17: 導入事例研究①'),
    (v_test_id,38,'「これだけで中古車販売ができます」というオーナーの発言が示すことは？','["システムが全業務を自動でこなす","symphony単体で中古車販売に必要な主要業務が完結する","他のシステムは一切不要になった","人手がゼロでも経営できる"]'::jsonb,1,'symphony 販売管理だけで在庫管理・広告掲載・粗利計算など中古車販売の主要業務が完結するという意味です。','研修17: 導入事例研究①'),
    (v_test_id,39,'中規模店舗B（在庫40台・スタッフ7名）の主な課題は？','["価格が高すぎる","営業と整備の情報共有ができず顧客フォロー漏れが発生","スタッフが多すぎる","在庫が少ない"]'::jsonb,1,'営業と整備の情報が分断されており、顧客フォロー漏れと仕入れルートの限界が課題でした。','研修18: 導入事例研究②'),
    (v_test_id,40,'中規模店舗B導入後、在庫回転率はどの程度向上したか？','["5%向上","50%向上","100%向上","25%向上"]'::jsonb,3,'販売管理とワンプラの連携により、在庫回転率が25%向上しました。','研修18: 導入事例研究②'),
    (v_test_id,41,'中規模店舗B導入後、年間売上はどの程度成長したか？','["1.1倍","2倍","1.5倍","1.3倍"]'::jsonb,3,'スタッフ全員が同じ情報を共有でき、在庫回転率も向上したことで年間売上が1.3倍に成長しました。','研修18: 導入事例研究②'),
    (v_test_id,42,'中規模店舗への提案で最も重視すべき訴求ポイントは？','["固定費の削減","スタッフ間の情報共有と在庫回転率向上","個人向け機能","海外展開サポート"]'::jsonb,1,'中規模店舗では情報共有の分断と在庫回転の非効率が課題です。販売管理での一元管理とワンプラでの仕入れ拡大を提案します。','研修18: 導入事例研究②'),
    (v_test_id,43,'大規模・多店舗企業C（3店舗・在庫150台・スタッフ25名）の主な課題は？','["新規スタッフの採用難","店舗ごとに管理がバラバラで本部でのリアルタイム把握ができない","顧客数が多すぎる","競合が多い地域にある"]'::jsonb,1,'店舗間の在庫・顧客管理がバラバラで連携が取れず、本部でのリアルタイムな状況把握にタイムラグがありました。','研修19: 導入事例研究③'),
    (v_test_id,44,'大規模企業への提案で最も重視すべき訴求ポイントは？','["低価格","使いやすい画面","全店舗の一元管理とデータに基づく経営判断の実現","個人の業績管理"]'::jsonb,2,'大規模企業では全店舗のデータ一元化と、それに基づく経営判断の高速化・精度向上が最重要課題です。','研修19: 導入事例研究③'),
    (v_test_id,45,'多店舗企業C導入後の年商増加率は？','["5%増","50%増","10%増","20%増"]'::jsonb,3,'全製品フル導入によりデータに基づく仕入れ・価格戦略の精度が向上し、グループ全体で年商が20%増加しました。','研修19: 導入事例研究③'),
    (v_test_id,46,'「データに基づく経営判断ができるようになった」という声が示すことは？','["勘や経験だけに頼った判断からリアルタイムデータを活用した判断への転換","売上データだけを見て判断する","競合他社のデータを参考にする","経営会議の回数を減らす"]'::jsonb,0,'symphonyシリーズのデータ一元化により、経験や勘だけに頼らずリアルタイムの数字を根拠とした意思決定ができるようになります。','研修19: 導入事例研究③'),
    (v_test_id,47,'ROIとは何の略か？','["Revenue Of Income","Return On Investment","Result Of Implementation","Rate Of Interest"]'::jsonb,1,'ROIはReturn On Investment（投資対効果）の略で、投資に対するリターンを示す指標です。','研修20: ROI計算の実践'),
    (v_test_id,48,'ROI計算で効果を算出する項目として適切でないのは？','["時間削減効果（コスト換算）","売上増加効果","コスト削減効果","競合他社の売上"]'::jsonb,3,'ROI計算では自社の時間削減・売上増加・コスト削減を金額換算します。競合他社の売上は関係ありません。','研修20: ROI計算の実践'),
    (v_test_id,49,'月20時間の削減・時給1,500円の場合、symphony導入による月の削減効果は？','["月1万円","月5万円","月3万円","月10万円"]'::jsonb,2,'月20時間×1,500円=月3万円の削減効果になります。さらに売上増加効果も加わります。','研修20: ROI計算の実践'),
    (v_test_id,50,'ROI計算を顧客に提示する最大の目的は？','["自社の利益を最大化するため","顧客に数字で効果を示し意思決定を後押しするため","競合他社と価格比較をするため","契約を急かすため"]'::jsonb,1,'「いくら儲かるのか」「いつ回収できるのか」を具体的な数字で示すことで、顧客の意思決定を論理的に後押しできます。','研修20: ROI計算の実践');
